            ),
            Text(" TextField -- WITH TextInputType.none"),
            SizedBox(height: 20),
            Container(
              width: 300,
              height: 100,
              child: TextField(keyboardType: TextInputType.none),
            ),
            Text("TextField -- WITHOUT  TextInputType.none"),
